diff --git a/pkg/bloom/filter.go b/pkg/bloom/filter.go
--- a/pkg/bloom/filter.go
+++ b/pkg/bloom/filter.go
@@ func (cf *CountingFilter) decrementCounter(pos uint64) {
 func (cf *CountingFilter) decrementCounter(pos uint64) {
 	byteIdx := pos / 2
 	if pos%2 == 0 {
 		low := cf.counters[byteIdx] & 0x0F
-		if low > 0 {
+		// A counter that has reached its 4-bit ceiling (15) is saturated:
+		// its true count is lost, so decrementing it could drive a still
+		// referenced position to zero and cause a false negative. Leave it.
+		if low > 0 && low < 15 {
 			cf.counters[byteIdx] = (cf.counters[byteIdx] & 0xF0) | (low - 1)
 		}
 	} else {
 		high := cf.counters[byteIdx] >> 4
-		if high > 0 {
+		if high > 0 && high < 15 {
 			cf.counters[byteIdx] = (cf.counters[byteIdx] & 0x0F) | ((high - 1) << 4)
 		}
 	}
 }
