+
+// TestCountingFilter_SaturatedCounterSurvives verifies that once a counter
+// saturates at its 4-bit ceiling it is no longer decremented, so a
+// still-referenced element is never reported as a false negative.
+func TestCountingFilter_SaturatedCounterSurvives(t *testing.T) {
+	cf := NewCountingFilter(1000, 0.01)
+	// Add many times so every counter position saturates at 15.
+	for i := 0; i < 20; i++ {
+		cf.Add([]byte("saturated"))
+	}
+	// Remove fewer times than we added; the element is still referenced.
+	for i := 0; i < 15; i++ {
+		if !cf.Remove([]byte("saturated")) {
+			t.Fatalf("remove %d should succeed", i)
+		}
+	}
+	if !cf.Contains([]byte("saturated")) {
+		t.Fatal("saturated, still-referenced element must not be a false negative")
+	}
+}
+
+// TestCountingFilter_NormalRoundTrip covers ordinary add/remove balance.
+func TestCountingFilter_NormalRoundTrip(t *testing.T) {
+	cf := NewCountingFilter(1000, 0.01)
+	cf.Add([]byte("a"))
+	cf.Add([]byte("a"))
+	cf.Add([]byte("a"))
+	cf.Remove([]byte("a"))
+	cf.Remove([]byte("a"))
+	if !cf.Contains([]byte("a")) {
+		t.Fatal("should still contain after net positive adds")
+	}
+	cf.Remove([]byte("a"))
+	if cf.Contains([]byte("a")) {
+		t.Fatal("should not contain after fully removed")
+	}
+}

