@@ -0,0 +1,49 @@
+package bloom
+
+import "testing"
+
+// Adding an element far beyond the 4-bit ceiling saturates its counters.
+// On the broken base, Remove decrements those saturated counters and can
+// drive them to zero, producing a false negative. The fix leaves saturated
+// counters untouched.
+func TestCountingFilter_SaturatedCounterNoFalseNegative(t *testing.T) {
+	cf := NewCountingFilter(1000, 0.01)
+	for i := 0; i < 20; i++ {
+		cf.Add([]byte("saturate"))
+	}
+	for i := 0; i < 18; i++ {
+		cf.Remove([]byte("saturate"))
+	}
+	if !cf.Contains([]byte("saturate")) {
+		t.Fatal("saturated counters must not produce false negatives")
+	}
+}
+
+func TestCountingFilter_NormalRoundTrip(t *testing.T) {
+	cf := NewCountingFilter(1000, 0.01)
+	cf.Add([]byte("a"))
+	cf.Add([]byte("a"))
+	cf.Remove([]byte("a"))
+	if !cf.Contains([]byte("a")) {
+		t.Fatal("should still contain after one of two removes")
+	}
+	cf.Remove([]byte("a"))
+	if cf.Contains([]byte("a")) {
+		t.Fatal("should not contain after both removes")
+	}
+}
+
+func TestFilter_FillRatioMatchesPopcount(t *testing.T) {
+	f := NewFilterRaw(1024, 7)
+	for i := 0; i < 50; i++ {
+		f.Add([]byte{byte(i)})
+	}
+	set := 0
+	for _, w := range f.bits {
+		for w != 0 {
+			set++
+			w &= w - 1
+		}
+	}
+	want := float64(set) / float64(f.size)
+	if f.FillRatio() != want {
+		t.Fatalf("FillRatio mismatch: got %v want %v", f.FillRatio(), want)
+	}
+}
